#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long l,r,lson,rson;
    long long sum,len;
}a[900010];
struct segment
{
    long long l,r,x,k,id;
    bool operator<(const segment&b)const
    {
        if(x==b.x)
        {
            return l>b.l;
        }
        return x<b.x;
    }
}p[400010];
long long cnt,n,ans,tot,k,y[300010];
void pushup(long long x)
{
    if(a[x].sum>0)
    {
        a[x].len=y[a[x].r]-y[a[x].l];
    }
    else
    {
        a[x].len=a[a[x].lson].len+a[a[x].rson].len;
    }
}
long long init(long long l,long long r)
{
    long long x=++cnt;
    a[x].l=l;
    a[x].r=r;
    a[x].sum=0;
    if(l+1==r)
    {
        a[x].len=0;
        return x;
    }
    long long mid=(l+r)>>1;
    a[x].lson=init(l,mid);
    a[x].rson=init(mid,r);
    pushup(x);
    return x;
}
void update(long long x,long long l,long long r,long long v)
{
    if(l>=y[a[x].r]||r<=y[a[x].l])
    {
        return;
    }
    if(l<=y[a[x].l]&&y[a[x].r]<=r)
    {
        // printf("a[%lld](%lld,%lld)+=%lld\n",x,a[x].l,a[x].r,v);
        a[x].sum+=v;
        pushup(x);
        return;
    }
    update(a[x].lson,l,r,v);
    update(a[x].rson,l,r,v);
    pushup(x);
}
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        long long ax,ay,bx,by;
        scanf("%lld%lld%lld%lld",&ax,&ay,&bx,&by);
        y[++tot]=ay;
        y[++tot]=by;
        p[++k]=(segment){ay,by,ax,1,i};
        p[++k]=(segment){ay,by,bx,-1,i};
    }
    sort(p+1,p+1+k);
    sort(y+1,y+1+tot);
    long long q=unique(y+1,y+1+tot)-y-1;
    init(1,q);
    // for(long long i=1;i<=q;i++)
    // {
    //     printf("y[%lld]=%lld\n",i,y[i]);
    // }
    for(long long i=1;i<k;i++)
    {
        update(1,p[i].l,p[i].r,p[i].k);
        // printf("update(1,%lld,%lld,%lld) a[1].len=%lld p[i].x=%lld\n",p[i].l,p[i].r,p[i].k,a[1].len,p[i].x);
        ans+=(p[i+1].x-p[i].x)*a[1].len;
    }
    printf("%lld",ans);
    return 0;
}
